import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
  Paper,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [docs, setDocs] = useState({ aadharFront: null, aadharBack: null, licenseImage: null });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData((p) => ({ ...p, [e.target.name]: e.target.value }));
  const handleFileChange = (e) => setDocs((p) => ({ ...p, [e.target.name]: e.target.files[0] }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await signupRider({ ...formData, role: "rider" });
      if (res.data?.success) {
        // Upload docs
        const token = res.data.token;
        const fd = new FormData();
        Object.entries(docs).forEach(([key, file]) => file && fd.append(key, file));
        await uploadRiderDocs(token, fd);

        setSuccess("Rider signup submitted. Pending approval.");
        setTimeout(() => navigate("/rider-login"), 1000);
      } else setError(res.data?.message || "Signup failed");
    } catch {
      setError("Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 3, borderRadius: 3, textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          Rider Signup
        </Typography>
        {error && <Alert severity="error">{error}</Alert>}
        {success && <Alert severity="success">{success}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" />
          <TextField fullWidth type="email" label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" />
          <TextField fullWidth type="tel" label="Mobile" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" />

          <Typography sx={{ mt: 2, fontWeight: "bold" }}>Upload Documents</Typography>
          <input type="file" name="aadharFront" onChange={handleFileChange} />
          <input type="file" name="aadharBack" onChange={handleFileChange} />
          <input type="file" name="licenseImage" onChange={handleFileChange} />

          <Button type="submit" fullWidth sx={{ mt: 2 }} disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Sign Up"}
          </Button>
        </Box>

        <Typography sx={{ mt: 2 }}>
          Already have a rider account? <Button onClick={() => navigate("/rider-login")}>Login</Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Are you a User? <Button onClick={() => navigate("/register")}>User Signup</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
